function createCustomFetch(config) {
  const fetchFn = config.customFetch || fetch;
  return async (fetchUrl, options) => {
    const headers = new Headers(options.headers);

    // Add User-Agent header
    headers.set(
      'User-Agent',
      config.httpUserAgent || `${pkg.name}/${pkg.version}`,
    );

    // Add telemetry header if enabled
    if (config.enableTelemetry) {
      headers.set(
        'Auth0-Client',
        Buffer.from(JSON.stringify(telemetryHeader)).toString('base64'),
      );
    }

    return fetchFn(fetchUrl, {
      ...options,
      headers,
    });
  };
}

async function getClientAuth(config) {
  switch (config.clientAuthMethod) {
    case 'client_secret_basic':
      return client.ClientSecretBasic(config.clientSecret);
    case 'client_secret_post':
      return client.ClientSecretPost(config.clientSecret);
    case 'client_secret_jwt':
      return client.ClientSecretJwt(config.clientSecret);
    case 'private_key_jwt': {
      const privateKey = await importPrivateKey(
        config.clientAssertionSigningKey,
        config.clientAssertionSigningAlg,
      );
      return client.PrivateKeyJwt(privateKey);
    }
    case 'none':
      return client.None();
    default:
      // Default based on whether client_secret is present
      if (config.clientSecret) {
        return client.ClientSecretPost(config.clientSecret);
      }
      return client.None();
  }
}

() => {
  // Try to use Joi.binary() if available (Node.js)
  if (typeof Joi.binary === 'function') {
    try {
      return Joi.binary().min(8);
    } catch {
      // Fall through to custom validator
    }
  }
  // Fallback for environments where Joi.binary() is not available
  return Joi.any()
    .custom((value, helpers) => {
      const isBufferLike =
        (typeof Buffer !== 'undefined' && Buffer.isBuffer(value)) ||
        value instanceof Uint8Array;

      if (!isBufferLike) {
        return helpers.error('binary.base');
      }
      if (value.length < 8) {
        return helpers.error('binary.min', { limit: 8 });
      }
      return value;
    })
    .messages({
      'binary.base': '{{#label}} must be a buffer',
      'binary.min': '{{#label}} must be at least {{#limit}} bytes',
    });
}

function tokenSet() {
  const contextCache = weakRef(this);
  const session = contextCache.req[contextCache.config.session.name];

  if (!session || !('id_token' in session)) {
    return undefined;
  }

  const cachedTokenSet = weakRef(session);

  if (!('value' in cachedTokenSet)) {
    const { id_token, access_token, refresh_token, token_type, expires_at } =
      session;
    cachedTokenSet.value = new TokenSet({
      id_token,
      access_token,
      refresh_token,
      token_type,
      expires_at,
    });
  }

  return cachedTokenSet.value;
}

module.exports = async (req, config) => {
  const store =
    (config.backchannelLogout && config.backchannelLogout.store) ||
    config.session.store;
  const get = safePromisify(store.get, store);
  const { serverMetadata } = await getClient(config);
  const issuer = serverMetadata.issuer;
  const { sid, sub } = req.oidc.idTokenClaims;
  if (!sid && !sub) {
    throw new Error(`The session must have a 'sid' or a 'sub'`);
  }
  const [logoutSid, logoutSub] = await Promise.all([
    sid && get(`${issuer}|${sid}`),
    sub && get(`${issuer}|${sub}`),
  ]);
  return !!(logoutSid || logoutSub);
};

module.exports = async (req, config) => {
  const { serverMetadata } = await getClient(config);
  const issuer = serverMetadata.issuer;
  const { session, backchannelLogout } = config;
  const store = (backchannelLogout && backchannelLogout.store) || session.store;
  const destroy = safePromisify(store.destroy, store);

  // Get the sub and sid from the ID token claims
  const { sub, sid } = req.oidc.idTokenClaims;

  // Remove both sub and sid based entries
  await Promise.all([
    destroy(`${issuer}|${sub}`),
    sid && destroy(`${issuer}|${sid}`),
  ]);
};

function _handlePreHookError(queryCursor, err) {
  if (err instanceof kareem.skipWrappedFunction) {
    const resultValue = err.args[0];
    if (resultValue != null && (!Array.isArray(resultValue) || resultValue.length)) {
      const err = new MongooseError(
        'Cannot `skipMiddlewareFunction()` with a value when using ' +
        '`.aggregate().cursor()`, value must be nullish or empty array, got "' +
        util.inspect(resultValue) +
        '".'
      );
      queryCursor._markError(err);
      queryCursor.listeners('error').length > 0 && queryCursor.emit('error', err);
      return;
    }
    queryCursor.emit('cursor', null);
    return;
  }
  queryCursor._markError(err);
  queryCursor.listeners('error').length > 0 && queryCursor.emit('error', err);
}

function _nextDoc(ctx, doc, pop, callback) {
  if (ctx.query._mongooseOptions.lean) {
    return ctx.model.hooks.execPost('find', ctx.query, [[doc]]).then(() => callback(null, doc), err => callback(err));
  }

  const { model, _fields, _userProvidedFields, options } = ctx.query;
  helpers.createModelAndInit(model, doc, _fields, _userProvidedFields, options, pop, (err, doc) => {
    if (err != null) {
      return callback(err);
    }
    if (options.session != null) {
      doc.$session(options.session);
    }
    ctx.model.hooks.execPost('find', ctx.query, [[doc]]).then(() => callback(null, doc), err => callback(err));
  });
}

function _handlePathsToValidate(paths, pathsToValidate) {
  const _pathsToValidate = new Set(pathsToValidate);
  const parentPaths = new Map([]);
  for (const path of pathsToValidate) {
    if (path.indexOf('.') === -1) {
      continue;
    }
    const pieces = path.split('.');
    let cur = pieces[0];
    for (let i = 1; i < pieces.length; ++i) {
      // Since we skip subpaths under single nested subdocs to
      // avoid double validation, we need to add back the
      // single nested subpath if the user asked for it (gh-8626)
      parentPaths.set(cur, path);
      cur = cur + '.' + pieces[i];
    }
  }

  const ret = new Set();
  for (const path of paths) {
    if (_pathsToValidate.has(path)) {
      ret.add(path);
    } else if (parentPaths.has(path)) {
      ret.add(parentPaths.get(path));
    }
  }
  return ret;
}

function _setTimestampsOnUpdate() {
  const schema = this.model.schema;
  const { createdAt, updatedAt } = schema.$timestamps;
  const timestamps = schema.options.timestamps;
  const currentTime = timestamps != null && Object.hasOwn(timestamps, 'currentTime') ?
    timestamps.currentTime :
    null;

  const now = currentTime != null ?
    currentTime() :
    this.model.base.now();
  // Replacing with null update should still trigger timestamps
  if (replaceOps.has(this.op) && this.getUpdate() == null) {
    this.setUpdate({});
  }
  applyTimestampsToUpdate(
    now,
    createdAt,
    updatedAt,
    this.getUpdate(),
    this._mongooseOptions,
    replaceOps.has(this.op)
  );
  applyTimestampsToChildren(now, this.getUpdate(), this.model.schema);
}

function completeOne(model, doc, res, options, fields, userProvidedFields, pop, callback) {
  if (options.includeResultMetadata && doc == null) {
    _init(null);
    return null;
  }

  helpers.createModelAndInit(model, doc, fields, userProvidedFields, options, pop, _init);

  function _init(err, casted) {
    if (err) {
      return callback(err);
    }


    if (options.includeResultMetadata) {
      if (doc && casted) {
        if (options.session != null) {
          casted.$session(options.session);
        }
        res.value = casted;
      } else {
        res.value = null;
      }
      return callback(null, res);
    }
    if (options.session != null) {
      casted.$session(options.session);
    }
    callback(null, casted);
  }
}

create(obj) {
  let Constructor = this[arraySchemaSymbol].Constructor;
  if (obj &&
      Constructor.discriminators &&
      Constructor.schema &&
      Constructor.schema.options &&
      Constructor.schema.options.discriminatorKey) {
    if (typeof obj[Constructor.schema.options.discriminatorKey] === 'string' &&
        Constructor.discriminators[obj[Constructor.schema.options.discriminatorKey]]) {
      Constructor = Constructor.discriminators[obj[Constructor.schema.options.discriminatorKey]];
    } else {
      const constructorByValue = getDiscriminatorByValue(Constructor.discriminators, obj[Constructor.schema.options.discriminatorKey]);
      if (constructorByValue) {
        Constructor = constructorByValue;
      }
    }
  }

  return new Constructor(obj, this);
}

getRouter(): express.Router {
  const router = Router();

  router.use(bodyParser.raw({ type: '*/*' }));

  router.post('/immediate/entities', async (req, res) => {
    if (!this.connection) {
      throw new Error(`Service is not yet initialized`);
    }
    const deferred = await this.getRequestBodyEntities(req);
    await this.connection.applyMutation({
      type: 'delta',
      added: deferred,
      removed: [],
    });
    res.status(201).end();
  });

  router.put('/immediate/entities', async (req, res) => {
    if (!this.connection) {
      throw new Error(`Service is not yet initialized`);
    }
    const deferred = await this.getRequestBodyEntities(req);
    await this.connection.applyMutation({
      type: 'full',
      entities: deferred,
    });
    res.status(201).end();
  });

  return router;
}

function formatMessage(startupResult: BackendStartupResult): string {
  const parts: string[] = [
    'Backend startup failed due to the following errors:',
  ];
  const failures: string[] = [];

  for (const plugin of startupResult.plugins) {
    if (plugin.failure && !plugin.failure.allowed) {
      failures.push(
        `  Plugin '${plugin.pluginId}' startup failed; caused by ${plugin.failure.error}`,
      );
    }

    for (const mod of plugin.modules) {
      if (mod.failure && !mod.failure.allowed) {
        failures.push(
          `  Module '${mod.moduleId}' for plugin '${plugin.pluginId}' startup failed; caused by ${mod.failure.error}`,
        );
      }
    }
  }

  if (failures.length > 0) {
    parts.push(...failures);
  }

  return parts.join('\n');
}

private matchesRule(
  action: ActionsServiceAction,
  rule: {
    idMatcher?: Minimatch;
    attributes?: Partial<
      Record<'destructive' | 'readOnly' | 'idempotent', boolean>
    >;
  },
): boolean {
  // If id pattern is specified, it must match
  if (rule.idMatcher && !rule.idMatcher.match(action.id)) {
    return false;
  }

  // If attributes are specified, all must match
  if (rule.attributes) {
    for (const [key, value] of Object.entries(rule.attributes)) {
      if (
        action.attributes[
          key as 'destructive' | 'readOnly' | 'idempotent'
        ] !== value
      ) {
        return false;
      }
    }
  }

  return true;
}

private async filterByPermissions(
  entries: ActionEntry[],
  credentials: BackstageCredentials,
): Promise<ActionEntry[]> {
  const permissionedEntries = entries.filter(
    ([_, action]) => action.visibilityPermission,
  );

  if (permissionedEntries.length === 0) {
    return entries;
  }

  const decisions = await this.permissions.authorize(
    permissionedEntries.map(([_, action]) => ({
      permission: action.visibilityPermission!,
    })),
    { credentials },
  );

  const deniedIds = new Set(
    permissionedEntries
      .filter((_, index) => decisions[index].result !== AuthorizeResult.ALLOW)
      .map(([id]) => id),
  );

  return entries.filter(([id]) => !deniedIds.has(id));
}

function json_hook(json) {
  let originalJson = json;
  res.json = original;
  if (res.headersSent) return res;
  if (!mungError && res.statusCode >= 500) return original.call(this, json);

  // Run the munger
  try {
    json = fn(json, req, res);
  } catch (e) {
    return mung.onError(e, req, res, next);
  }
  if (res.headersSent) return res;

  // If no returned value from fn, then assume json has been mucked with.
  if (json === undefined) json = originalJson;

  // If null, then 204 No Content
  if (json === null) return res.status(204).end();

  // If munged scalar value, then text/plain
  if (originalJson !== json && isScalar(json)) {
    res.set('content-type', 'text/plain');
    return res.send(String(json));
  }

  return original.call(this, json);
}

public _getOrBuildValidator(
  req: OpenApiRequest,
  responses: OpenAPIV3.ResponsesObject,
): { [key: string]: ValidateFunction } {
  // get the request content type - used only to build the cache key
  const contentTypeMeta = ContentType.from(req);
  const contentType = contentTypeMeta.normalize() ?? 'not_provided';

  const openapi = <OpenApiRequestMetadata>req.openapi;
  const key = `${req.method}-${openapi.expressRoute}-${contentType}`;

  let validators = this.validatorsCache[key];
  if (!validators) {
    validators = this.buildValidators(responses, key);
    this.validatorsCache[key] = validators;
  }
  return validators;
}

private extractRequestBodySchemaNodes(
  node: Root<OpenAPIV3.OperationObject>,
): Root<SchemaObject>[] {
  const op = node.schema;
  const bodySchema = this.resolveSchema<OpenAPIV3.RequestBodyObject>(
    op.requestBody,
  );
  op.requestBody = bodySchema;

  if (!bodySchema?.content) return [];

  const result: Root<SchemaObject>[] = [];
  const contentEntries = Object.entries(bodySchema.content);
  for (const [type, mediaTypeObject] of contentEntries) {
    const mediaTypeSchema = this.resolveSchema<SchemaObject>(
      mediaTypeObject.schema,
    );
    op.requestBody.content[type].schema = mediaTypeSchema;

    // TODO replace with visitor
    this.removeExamples(op.requestBody.content[type]);

    const path = [...node.path, 'requestBody', 'content', type, 'schema'];
    result.push(new Root(mediaTypeSchema, path));
  }
  return result;
}

export function augmentAjvErrors(errors: ErrorObject[] = []): ErrorObject[] {
  errors.forEach((e) => {
    if (e.keyword === 'enum') {
      const params: any = e.params;
      const allowedEnumValues = params?.allowedValues;
      e.message = !!allowedEnumValues
        ? `${e.message}: ${allowedEnumValues.join(', ')}`
        : e.message;
    }
  });
  const serDesPaths = new Set<string>();
  return errors.filter((e) => {
    if (serDesPaths.has(e.schemaPath)) {
      return false;
    }
    if (e.params['x-eov-res-serdes']) {
      // If response serialization failed,
      // silence additional errors about not being a string.
      serDesPaths.add(e.schemaPath.replace('x-eov-res-serdes', 'x-eov-type'));
    }
    return true;
  });
}

installPathParams(app: Application | Router, context: OpenApiContext): void {
  const pathParams: string[] = [];
  for (const route of context.routes) {
    if (route.pathParams.length > 0) {
      pathParams.push(...route.pathParams);
    }
  }

  // install param on routes with paths
  const uniqPathParams = [...new Set(pathParams)]
  for (const p of uniqPathParams) {
    app.param(
      p,
      (
        req: OpenApiRequest,
        res: Response,
        next: NextFunction,
        value: any,
        name: string,
      ) => {
        const openapi = <OpenApiRequestMetadata>req.openapi;
        if (openapi?.pathParams) {
          const { pathParams } = openapi;
          // override path params
          req.params[name] = pathParams[name] || req.params[name];
        }
        next();
      },
    );
  }
}

const setLegacyHeaders = (
	response: Response,
	info: RateLimitInfo,
): void => {
	if (response.headersSent) return

	response.setHeader('X-RateLimit-Limit', info.limit.toString())
	response.setHeader('X-RateLimit-Remaining', info.remaining.toString())

	// If we have a resetTime, also provide the current date to help avoid
	// issues with incorrect clocks.
	if (info.resetTime instanceof Date) {
		response.setHeader('Date', new Date().toUTCString())
		response.setHeader(
			'X-RateLimit-Reset',
			Math.ceil(info.resetTime.getTime() / 1000).toString(),
		)
	}
}

const setDraft6Headers = (
	response: Response,
	info: RateLimitInfo,
	windowMs: number,
): void => {
	if (response.headersSent) return

	const windowSeconds = Math.ceil(windowMs / 1000)
	const resetSeconds = getResetSeconds(windowMs, info.resetTime)

	response.setHeader('RateLimit-Policy', `${info.limit};w=${windowSeconds}`)
	response.setHeader('RateLimit-Limit', info.limit.toString())
	response.setHeader('RateLimit-Remaining', info.remaining.toString())

	// Set this header only if the store returns a `resetTime`.
	if (typeof resetSeconds === 'number')
		response.setHeader('RateLimit-Reset', resetSeconds.toString())
}

const setDraft8Headers = (
	response: Response,
	info: RateLimitInfo,
	windowMs: number,
	name: string,
	key: string,
): void => {
	if (response.headersSent) return

	const windowSeconds = Math.ceil(windowMs / 1000)
	const resetSeconds = getResetSeconds(windowMs, info.resetTime)
	const partitionKey = getPartitionKey(key)

	const header = `r=${info.remaining}; t=${resetSeconds}`
	const policy = `q=${info.limit}; w=${windowSeconds}; pk=:${partitionKey}:`

	response.append('RateLimit', `"${name}"; ${header}`)
	response.append('RateLimit-Policy', `"${name}"; ${policy}`)
}

singleCount(request: Request, store: Store, key: string) {
	let storeKeys = singleCountKeys.get(request)
	if (!storeKeys) {
		storeKeys = new Map()
		singleCountKeys.set(request, storeKeys)
	}

	const storeKey = store.localKeys ? store : store.constructor.name
	let keys = storeKeys.get(storeKey)
	if (!keys) {
		keys = []
		storeKeys.set(storeKey, keys)
	}

	const prefixedKey = `${store.prefix ?? ''}${key}`

	if (keys.includes(prefixedKey)) {
		throw new ValidationError(
			'ERR_ERL_DOUBLE_COUNT',
			`The hit count for ${key} was incremented more than once for a single request.`,
		)
	}

	keys.push(prefixedKey)
}

async run(context: Context, value: any, meta: Meta) {
  try {
    const result = this.validator(value, meta);
    const actualResult = await result;
    const isPromise = result?.then;
    const failed = this.negated ? actualResult : !actualResult;

    // A promise that was resolved only adds an error if negated.
    // Otherwise it always succeeds
    if ((!isPromise && failed) || (isPromise && this.negated)) {
      context.addError({ type: 'field', message: this.message, value, meta });
    }
  } catch (err) {
    if (this.negated) {
      return;
    }

    context.addError({
      type: 'field',
      message: this.message || (err instanceof Error ? err.message : err),
      value,
      meta,
    });
  }
}

async run(context: Context, value: any, meta: Meta) {
  const { path, location } = meta;

  const runCustomSanitizer = async () => {
    const sanitizerValue = this.sanitizer(value, meta);
    return Promise.resolve(sanitizerValue);
  };

  if (this.custom) {
    const newValue = await runCustomSanitizer();
    context.setData(path, newValue, location);
    return;
  }
  const values = Array.isArray(value) ? value : [value];
  const newValues = values.map(value => {
    return (this.sanitizer as StandardSanitizer)(this.stringify(value), ...this.options);
  });

  // We get only the first value of the array if the original value was wrapped.
  context.setData(path, values !== value ? newValues[0] : newValues, location);
}

private createChain(
  fields: string | string[] = '',
  locations: Location[] = [],
  message?: any,
): CustomValidationChain<this> {
  const middleware = check(fields, locations, message) as CustomValidationChain<this>;

  const boundValidators = Object.fromEntries(
    this.validatorEntries.map(([name, fn]) => [name, () => middleware.custom(fn)]),
  ) as Record<keyof V, () => CustomValidationChain<this>>;

  const boundSanitizers = Object.fromEntries(
    this.sanitizerEntries.map(([name, fn]) => [name, () => middleware.customSanitizer(fn)]),
  ) as Record<keyof S, () => CustomValidationChain<this>>;

  return Object.assign(middleware, boundValidators, boundSanitizers);
}

export function matchedData<T extends object = Record<string, any>>(
  req: Request,
  options: Partial<MatchedDataOptions> = {},
): T {
  const internalReq: InternalRequest = req;

  const fieldExtractor = createFieldExtractor(options.includeOptionals !== true);
  const validityFilter = createValidityFilter(options.onlyValidData);
  const locationFilter = createLocationFilter(options.locations);

  return _(internalReq[contextsKey])
    .flatMap(fieldExtractor)
    .filter(validityFilter)
    .map(field => field.instance)
    .filter(locationFilter)
    .reduce((state, instance) => _.set(state, instance.path, instance.value), {} as T);
}
